+
+    std::string trimString(std::string str)
+    {
+        for (std::string::size_type s = str.length() - 1; s > 0; --s)
+        {
+            if (str[s] == '0' && !isdigit(str[s - 1]))
+                break;
+            else if (str[s] == '0')
+                str.erase(s, 1);
+            else
+                break;
+        }
+        return str;
+    }
